  render: () => {
    const [startDate, setStartDate] = useState<Date | null>(null);
    const [endDate, setEndDate] = useState<Date | null>(null);
    const today = new Date();
    const maxDate = new Date();
    maxDate.setDate(today.getDate() + 365);
    return <div className="flex flex-col gap-4 max-w-md">
        <DatePicker label="Start Date" placeholder="Select start date" value={startDate} onChange={date => {
        setStartDate(date);
        if (endDate && date && endDate < date) {
          setEndDate(null);
        }
      }} minDate={today} maxDate={maxDate} clearable helperText="Select a start date for your event" required />
        <DatePicker label="End Date" placeholder="Select end date" value={endDate} onChange={setEndDate} minDate={startDate || today} maxDate={maxDate} clearable disabled={!startDate} helperText={!startDate ? 'Please select a start date first' : 'Must be after start date'} required />
      </div>;
  }
